function solution(alp, cop, problems) {
    var answer = 15000;

    let max_alp=alp, max_cop=cop;
    problems.forEach(p=>{
        if(p[0]>max_alp) max_alp = p[0]
        if(p[1]>max_cop) max_cop = p[1]
    })

    const dp = Array(max_alp+1).fill(0).map(v=>Array(max_cop+1).fill(15000))
    // dp[i][j]=k i알고력, j코딩력을 얻는 데에 드는 최소 시간 k
    dp[alp][cop] = 0

    let i=alp, j=cop;
    while(i<=max_alp && j<=max_cop){
        if(i<max_alp){
            // 알고리즘 공부
            dp[i+1][j] = Math.min(dp[i+1][j], dp[i][j]+1)
            updateAnswer(i+1, j, Math.min(dp[i+1][j], dp[i][j]+1))
        }

        if(j<max_cop){
            // 코딩 공부
            dp[i][j+1] = Math.min(dp[i][j+1], dp[i][j]+1)
            updateAnswer(i, j+1, Math.min(dp[i][j+1], dp[i][j]+1))
        }

        // 문제풀이
        problems.forEach(([alp_req, cop_req, alp_rwd, cop_rwd, cost])=>{
            if(i<alp_req || j<cop_req) return
            const nextI = Math.min(i+alp_rwd, max_alp)
            const nextJ = Math.min(j+cop_rwd, max_cop)
            dp[nextI][nextJ] = Math.min(dp[nextI][nextJ], dp[i][j]+cost)
            updateAnswer(nextI, nextJ, Math.min(dp[nextI][nextJ], dp[i][j]+cost))
        })
        j++
        if(j>max_cop){
            j=cop
            i++
        }
    }
    // console.log(dp)
    return answer;

    function updateAnswer(alPower, coPower, val){
        if(
            alPower >= max_alp
            && coPower>=max_cop
            && answer>val
        ) {
            answer = val
        }
    }
}

import java.io.*;
import java.util.*;
class Solution {
    ArrayList<int[]>[] edges;
    int[] nodes;
    final int MAX_INTENSITY = 10000001;
    final int GATE = 1;
    final int SUMMIT = 2;
    int minIntensity = MAX_INTENSITY;
    public int[] solution(int n, int[][] paths, int[] gates, int[] summits) throws IOException{
        int[] answer = {0, MAX_INTENSITY};

        nodes = new int[n];
        for(int gate:gates){
            nodes[gate-1] = GATE;
        }
        for(int summit:summits){
            nodes[summit-1] = SUMMIT;
        }
        Arrays.sort(summits);

        edges = new ArrayList[n];
        for(int i=0; i<n; i++){
            edges[i] = new ArrayList<>();
        }

        for(int i=0; i<paths.length; i++){
            int from = paths[i][0]-1;
            int to = paths[i][1]-1;
            int cost = paths[i][2];
            edges[from].add(new int[]{to, cost});
            edges[to].add(new int[]{from, cost});
        }

        for(int i=0; i<summits.length; i++){
            // 각 봉우리로부터 gate 찾기 dijkstra는 최소 intensity를 보장한다.
            int intensity = Dijkstra(n, summits[i]-1);
            if(intensity < answer[1]) {
                answer[0] = summits[i];
                answer[1] = intensity;
                minIntensity = intensity;
            }
        }
        return answer;
    }

    int Dijkstra(int n, int from){
        int intensity = 0;
        boolean[] visited = new boolean[n];
        visited[from] = true;

        PriorityQueue<int[]> q = new PriorityQueue<>((a, b)->Integer.compare(a[1], b[1]));

        q.add(new int[]{from, 0});

        while(!q.isEmpty()){
            int[] cur = q.poll();
            visited[cur[0]] = true;
            if(cur[1]>intensity){
                intensity = cur[1];
                if(intensity >= minIntensity) return MAX_INTENSITY;
            }
            if(nodes[cur[0]] == GATE) return intensity;
            for(int[] to: edges[cur[0]]){
                if(visited[to[0]]) continue; // visited
                if(nodes[to[0]] == SUMMIT) continue; // 봉우리
                q.add(new int[]{to[0], to[1]});
            }
        }
        System.out.println("WHY IS THIS PRINTING?");
        return MAX_INTENSITY;
    }
}

