function bfs(index){
    const nodes = [index]

    while(nodes.length>0){
        let node = nodes.shift()
        const cost = costs[node]
        edges[node].forEach(next=>{
            if(costs[next]<=cost+1) return
            costs[next] = cost+1
            nodes.push(next)
        })
    }
}

