/**
리프노드에 도달하는 순서는 정해져있다.
이 순서를 파악하고, 가장 빨리 target을 만드는 조합을 만들면 될 듯?

입출력 예 #1

target [0, 0, 0, 3, 0, 0, 5, 1, 2, 3]
도달순서 [4, 8, 7, 9, 4, 10, 7, ...]
result [1, 1, 2, 2, 2, 3, 3]

1. 각 노드의 최소 도달 횟수를 구한다.
2. 이를 만족하는 리프 도달 순서 배열을 구한다.
    2.1 각 노드의 길 상태 유지 필요
3. 이 리프 배열을 사전순으로 채운다.
    3.1 우선 1로 모두 채운다.
    3.2 부족한 만큼 3으로 채워보고,
    3.3 부족한 만큼 2로 채운다.
*/

function solution(e, target) {
    const res = [];
    const l = target.length;

    let edges = Array(l).fill(0).map(_=>[]);

    e.forEach(([from, to])=>{
        from--;
        to--;
        edges[from].push(to);
    })

    // edges = edges.map(arr=>arr.sort());
    edges = edges.map(arr => arr.sort((a, b) => a - b));

    const path_indexes = Array(l).fill(-1);
    edges.forEach((children, i)=>{
        if(children.length>0)
            path_indexes[i] = 0;
    })

    // 1. 각 노드의 최소 도달 횟수를 구한다.
    const min_card_amounts = target.map(n=>Math.ceil(n/3));

    // 2. 이를 만족하는 리프 도달 배열을 구한다.
    const leaf_order = [];
    const card_amounts = Array(l).fill(0);

    while(!isArrayGTE(card_amounts, min_card_amounts)){
        simulate(0);
    }

    // 불가 판단
    for(let i=0; i<l; i++){
        if(target[i] < card_amounts[i]) return [-1];
    }

    // 입력 순서 계산
    const input_order = target.map((t,i)=>get_card_order(t, card_amounts[i]).reverse());

    // console.log(card_amounts)
    // console.log(leaf_order)
    // console.log(input_order)

    leaf_order.forEach(n=>{
        res.push(input_order[n].pop());
    })

    return res

    function simulate(node){
        let children = edges[node];
        let cur_node = node;
        while(children.length>0){
            const cur_path_index = path_indexes[cur_node];
            path_indexes[cur_node] = (cur_path_index+1)%children.length;
            cur_node = children[cur_path_index];
            children = edges[cur_node];
        }
        card_amounts[cur_node]++;
        leaf_order.push(cur_node);
    }
}

function isArrayGTE(arr, min_arr){
    for(let i=0; i<arr.length; i++)
        if(arr[i]<min_arr[i]) return false;
    return true;
}

function get_card_order(target_sum, amount){
    // amount개의 1,2,3으로 target_sum을 만들 수 있는 방법 중
    // 사전 순으로 가장 빠른 방법 구하기
    // *amount는 target_sum보다 작지 않다.
    // *amount는 target_sum*3보다 크지 않다.

    // fill with 1
    const cards = Array(amount).fill(1);
    let cur_sum = amount;
    let diff = target_sum - cur_sum;
    let last_unfilled_index = amount-1;

    // fill with 3
    const fill_length = Math.floor(diff/2);
    cards.fill(3, amount-fill_length);
    last_unfilled_index = amount-fill_length-1;
    diff %= 2;

    // fill with 2
    if(diff == 1){
        cards[last_unfilled_index] ++;
    }

    return cards;
}

// u r l d (사전역순)
const ds = [[-1, 0, 'u'], [0, 1, 'r'], [0, -1, 'l'], [1, 0, 'd']]

function solution(H, W, y, x, r, c, k) {
    y--;x--;r--;c--;

    const distances = Array.from({length:H}, (_, ty)=>
                           Array.from({length: W}, (__, tx)=>
                              distanceBetween(ty, tx, r, c)))

    if(distances[y][x] > k || distances[y][x]%2 != k%2) return 'impossible'

    const startNode = {ty: y, tx: x, depth: 0, path: ""}
    const queue = [startNode]

    // dfs
    while(queue.length>0){
        const {ty, tx, depth, path} = queue.pop()
        if(distances[ty][tx]>k-depth) continue
        if(ty===r && tx===c && depth===k) return path

        ds.forEach(([dy, dx, dir])=>{
            const ny = ty + dy
            const nx = tx + dx

            if(ny<0||nx<0||ny>=H||nx>=W) return
            queue.push({ty: ny, tx: nx, depth: depth+1, path: path + dir})
        })
    }

    return "impossible";

    function distanceBetween(y1, x1, y2, x2){
        return Math.abs(x1-x2) + Math.abs(y1-y2)
    }
}

function toBinary(n){
    const str = n.toString(2)

    let length = str.length
    let saturatedLength = 2
    while(saturatedLength-1<length)saturatedLength*=2

    return str.padStart(saturatedLength-1, '0')
}

// 포화로 만들었을 때, 이진수의 중앙값이 0이면 나머지도 0이어야 한다.
// 길이가 1일 때까지 반복 (분할정복)

function solution(numbers) {
    var answer = [];

    const binaries = numbers.map(toBinary)
    binaries.forEach(b=>{
        answer.push(check(b)?1:0)
    })

    function check(binary, shouldZero=false){
        // length should be always odd
        if(binary.length==0) return true
        const middleIndex = Number.parseInt(binary.length/2)
        const front = binary.slice(0, middleIndex)
        const rear = binary.slice(middleIndex+1)
        // console.log('----', binary)
        // console.log(front)
        // console.log(rear)
        if(binary[middleIndex] == '1'){
            if(shouldZero) return false
            else return check(front) && check(rear)
        } else{
            // all sides should be zero
            return check(front, true) && check(rear, true)
        }
