function solution(m, n, startX, startY, balls) {
    var answer = [];

    balls.forEach(([x, y])=>{
        answer.push(getMinDistSquare(x, y))
    })

    return answer;

    function getMinDistSquare(targetX, targetY){
        let dists = []


        // 동
        if(startX>targetX || startY!=targetY){
            let newX = startX + (m-startX)*2
            let newY = startY
            dists.push(Math.pow(newX-targetX,2) + Math.pow(newY-targetY,2))
        }


        // 서
        if(startX<targetX || startY!=targetY){
            newX = -startX
            newY = startY
            dists.push(Math.pow(newX-targetX,2) + Math.pow(newY-targetY,2))
        }

        // 남
        if(startY<targetY || startX!=targetX){
            newX = startX
            newY = -startY
            dists.push(Math.pow(newX-targetX,2) + Math.pow(newY-targetY,2))
        }

        // 북
        if(startY>targetY || startX!=targetX){
            newX = startX
            newY = startY + (n-startY)*2
            dists.push(Math.pow(newX-targetX,2) + Math.pow(newY-targetY,2))
        }

        return Math.min(...dists)
    }
}

const visit = Array(100).fill(0).map(v=>Array(100).fill(false))
const DIRS = [[-1,0], [1,0], [0,-1], [0,1]]
let board_g

function solution(board) {
    board_g = board.map(str=>str.split(''))
    var answer = -1;
    let start, end;
    board_g.forEach((arr, i)=>{
        arr.forEach((v, j)=>{
            if(v=='G') end = [i, j]
            else if(v=='R') start = [i, j]
        })
    })

    // bfs
    let nodes = [[...start, 0]]
    while(nodes.length>0){
        let cur = nodes.shift()
        const depth = cur[2]

        if(cur[0]==end[0] && cur[1]==end[1]){
            answer = depth
            break
        }

        DIRS.forEach(d=>{
            let next = getNext(cur, d)
            if(visit[next[0]][next[1]]) return
            visit[next[0]][next[1]] = true
            nodes.push([next[0], next[1], depth+1])
        })
    }

    return answer;
}

function getNext(from, d){
    let curY = from[0]
    let curX = from[1]
    let nextY = curY+d[0]
    let nextX = curX+d[1]
    while(true){
        if( nextY<0 || nextY>=board_g.length
           || nextX<0 || nextX>=board_g[0].length
           || board_g[nextY][nextX]=='D'
          )
            break
        curY = nextY
        curX = nextX
        nextY += d[0]
        nextX += d[1]
    }
    return [curY, curX]
}

function solution(n, t, m, timetable) {
    // 마지막에 타는 사람 -1분 혹은 마지막에 오는 셔틀 시간
    timetable.sort()
    timetable.reverse()

    let hour=9
    let min=0

    let answer = [0, 0]

    for(let i=0; i<n; i++){
        if(i>0) [hour, min] = tictoc(hour, min, t)
        let onboard = 0

        if(i==n-1){ // last bus
            while(onboard<m){
                if(timetable.length==0) {
                    answer = [hour, min]
                    break
                }
                let [next_h, next_m] = parseTime(timetable[timetable.length-1])
                if(next_h>hour || (next_h==hour && next_m>min)){
                    answer = [hour, min]
                    break
                }
                onboard++
                let [last_h, last_m] = parseTime(timetable.pop())
                if(onboard==m){
                    if(last_m==0){
                        last_h--
                        last_m = 59
                    } else last_m--
                    answer = [last_h, last_m]
                }
            }
        } else{
            while(onboard<m){
                if(timetable.length==0) break
                let [next_h, next_m] = parseTime(timetable[timetable.length-1])
                if(next_h>hour || (next_h==hour && next_m>min)) break
                onboard++
                timetable.pop()
            }
        }
    }

    return parseString(answer)

    function tictoc(hour, min, term){
        min = min+term
        if(min>=60){
            hour++
            min-=60
        }

        return [hour, min]
    }

    function parseTime(timeString){
        let [h, m] = timeString.split(':')
        return [Number(h), Number(m)]
    }

    function parseString([hour, min]){
        let res = ""
        if(hour<10) res = "0"
        res += hour
        res += ":"
        if(min<10) res += "0"
        res += min
        return res
    }
}

