const ds = [[1,0], [-1,0], [0,1], [0,-1]]

function searchOilArea(){
    let currentType = 2
    for(let y=0; y<LAND.length; y++){
        for(let x=0; x<LAND[0].length; x++){
            if(LAND[y][x]!=1) continue

            // bfs
            let currentSize = 0
            const q = [[y,x]]
            LAND[y][x] = currentType

            while(q.length>0){
                const [curY, curX] = q.pop()
                currentSize++

                ds.forEach(([dy, dx])=>{
                    const ny = curY+dy
                    const nx = curX+dx

                    if(ny<0 || ny>=LAND.length || nx<0 || nx>=LAND[0].length) return
                    if(LAND[ny][nx]!=1) return

                    LAND[ny][nx] = currentType
                    q.push([ny, nx])
                })
            }

            areaSizeByType.set(currentType++, currentSize)
        }
    }
}

function solution(coin, cards) {
    var answer = 1;

    const n = cards.length
    const card_index = new Map()
    const combisByCost = [[],[],[]]

    // search combinations
    cards.forEach((v, i)=>{
        card_index.set(v, i) // v는 i번째에 있어요.
    })

    cards.forEach((v,i)=>{
        if(v>(n+1)/2) return
        const other = n+1-v
        const other_i = card_index.get(other)
        const newCombi = i<other_i?[i, other_i]:[other_i, i]
        if(newCombi[1]<n/3) combisByCost[0].push(newCombi)
        else if(newCombi[0]<n/3) combisByCost[1].push(newCombi)
        else combisByCost[2].push(newCombi)
    })

    // 뒷 카드순 정렬
    combisByCost.forEach(combis=>combis.sort((a,b)=>a[1]-b[1]))

    let index = n/3-1 + 2
    while(index<=n){

        let flag = false
        let pair

        if(combisByCost[0].length>0){
            flag = true
            pair = combisByCost[0].splice(0,1)
        } 
        if(!flag && combisByCost[1].length>0 && coin>=1){
            if(combisByCost[1][0][1]<=index){
                flag = true
                coin--
                pair = combisByCost[1].splice(0, 1)
            }
        }
        if(!flag && combisByCost[2].length>0 && coin>=2){
            if(combisByCost[2][0][1]<=index){
                flag = true
                coin -= 2
                pair = combisByCost[2].splice(0, 1)
            }
        }

        if(!flag){
            break
        }
        // console.log('pair: ', pair)

        index += 2
        answer += 1
    }

    return answer;
}

function solution(dice) {
    var answer = [];
    let maxWins = 0

    pickDices(pick, [], -1)

    // 252
    function pickDices(callback, currentDices, flag){
        if(currentDices.length == dice.length/2){
            return callback(currentDices)
        }
        for(let i=flag+1; i<dice.length; i++){
            pickDices(callback, [...currentDices, i], i)
        }
    }

    function pick(dicesA){
        let winCount = 0
        let loseCount = 0

        // A has dicesA.
        // B has rest of it.
        const dicesB = []
        for(let i=0; i<dice.length; i++){
            if(dicesA.indexOf(i)!=-1) {
                continue
            }
            dicesB.push(i)
        }

        // roll
        const eyesA = getSumCounts(dicesA)
        const eyesB = getSumCounts(dicesB)

        eyesA.forEach((Acount, Asum)=>{
            eyesB.forEach((Bcount, Bsum)=>{
                if(Asum>Bsum){
                    winCount += Acount * Bcount
                    if(winCount > maxWins){
                        maxWins = winCount
                        answer = dicesA.map(v=>v+1)
                    }
                } else{
                    loseCount += Acount * Bcount
                }
            })
        })
    }

    function getSumCounts(dices){
        const sumCounts = new Map()
        rollDice(0, dices, 0, sumCounts)
        return sumCounts
    }

    function rollDice(currentSum, dices, index, sumCounts){
        if(index==dices.length){
            if(!sumCounts.has(currentSum))
                sumCounts.set(currentSum, 0)
            return sumCounts.set(currentSum, sumCounts.get(currentSum)+1)
        }
        for(let i=0; i<6; i++){
            rollDice(currentSum + dice[dices[index]][i], dices, index+1, sumCounts)
        }
    }

    return answer;
}

