function nextMove(from, to){
    if(from[0]<to[0]) return [1,0]
    else if(from[0]>to[0]) return [-1,0]
    else if(from[1]<to[1]) return [0, 1]
    else if(from[1]>to[1]) return [0, -1]

    return [0,0]
}

