function solve(level){
    let time=0
    let d
    for(let i=0; i<DIFFS.length; i++){
        if(DIFFS[i]>level){
            d = DIFFS[i]-level
            time+= TIMES[i]*(d+1) + TIMES[i-1]*d
        } else{
            time+= TIMES[i]
        }

        if(time>LIMIT) return false
    }
    return true
}

