        if(visited.get(node)) return
        const newTree = []

        // dfs
        const q = [node]
        while(q.length>0){
            const node = q.pop()
            if(visited.get(node)) continue
            visited.set(node, true)
            newTree.push(node)
            const nearNodes = edgeMap.get(node)
            if(!nearNodes) continue
            nearNodes.forEach(n=>q.push(n))
        }

        trees.push(newTree)
