            if(node%2==0){
                if(edgeCount.get(node)%2==0){
                    // 짝수인데 자식도 짝수개

                    // 루트가 되어야 짝수노드임
                    if(HJRoot){
                        canHJ=false
                    } else{
                        HJRoot = true
                    }

                    // 루트가 안되어야 역짝수노드임

                } else{
                    // 짝수인데 자식은 홀수개

                    // 루트가 안되어야 짝수노드임

                    // 루트가 되어야 역짝수노드임
                    if(RHJRoot){
                        canRHJ=false
                    } else{
                        RHJRoot = true
                    }
                }
            } else{
                if(edgeCount.get(node)%2==0){
                    // 홀수인데 자식은 짝수개

                    // 루트가 안되어야 짝수노드임

                    // 루트가 되어야 역짝수노드임
                    if(RHJRoot){
                        canRHJ=false
                    } else{
                        RHJRoot = true
                    }

                } else{
                    // 홀수인데 자식도 홀수개

                    // 루트가 되어야 짝수노드임
                    if(HJRoot){
                        canHJ=false
                    } else{
                        HJRoot = true
                    }

                    // 루트가 되어야 역짝수노드임
