        return 0
    answer = 100
    #링크테이블 만들기
    words.insert(0, begin)
    targetIdx = words.index(target)
    linkTable = [[0 for _ in range(len(words))] for __ in range(len(words))]
    for i in range(len(linkTable)):
        for j in range(len(linkTable[i])):
            if isConvertible(words[i], words[j]):
                linkTable[i][j] = 1
    q = deque([(0, 0)])
    visited = set({})
    while q:
        idx, cost = q.popleft()
        if idx == targetIdx:
            if answer > cost:
                answer = cost
            continue
        if idx in visited:
            continue
        visited.add(idx)

        for j in range(len(linkTable[idx])):
            if linkTable[idx][j]:
                q.append((j, cost+1))
    if answer == 100:
        return 0
    return answer

