function solution(key, lock) {
    let holes = lock.reduce((last_val, new_val)=>
        last_val+new_val.filter(v=>v==0).length
        , 0)

    let keys = []
    for(let i=0; i<4; i++){
        keys.push(key)
        key = rotate(key)
    }

    let M = key.length
    let N = lock.length
    let lock_w_pad = Array(N+(M-1)*2).fill(0).map(v=>Array(N+(M-1)*2).fill(2))
    for(let i=M-1; i<N+M-1; i++){
        for(let j=M-1; j<N+M-1; j++){
            lock_w_pad[i][j]=lock[i-M+1][j-M+1]
        }
    }

    for(let i=0; i<N+M-1; i++){
        for(let j=0; j<N+M-1; j++){
            for(let k=0; k<4; k++){
                if(fit(i, j, k)) return true
            }
        }
    }

    return false

    function rotate(arr){
        let height = arr.length
        let width = arr[0].length
        let new_arr = Array(height).fill(0).map(v=>Array(width))

        for(let i=0; i<height; i++){
            for(let j=0; j<width; j++){
                new_arr[i][j] = arr[height-j-1][i]
            }
        }

        return new_arr
    }

    function fit(y, x, k){
        let key = keys[k]
        let tmp_holes = holes
        for(let i=0; i<M; i++){
            for(let j=0; j<M; j++){
                let lock_y = y + i
                let lock_x = x + j
                if(key[i][j]==lock_w_pad[lock_y][lock_x]) return false
                if(key[i][j]==1 && lock_w_pad[lock_y][lock_x]==0) tmp_holes--
            }
        }

        if(tmp_holes==0) return true
        return false
    }
}

// 최대 단어 개수 100_000 개
// 최대 단어 길이 10_000 글자
// 최대 키워드 개수 100_000 개
// 최대 키워드 길이 10_000 글자
function solution(words, queries) {
    const result = []

    // words에 대한 Trie 생성
    const postfix = new Trie()
    const prefix = new Trie()

    // Trie에 입력
    words.forEach((word)=>{
        postfix.add(word)
        prefix.add(reverseString(word))
    })

    // query 호출
    queries.forEach((query)=>{
        if(query[0]=='?') result.push(prefix.searchAmount(reverseString(query)))
        else result.push(postfix.searchAmount(query))
    })

    return result

    function reverseString(string){
        return Array.from(string).reverse().join("")
    }
}

class Node{
    constructor(key, value){
        this.key = key
        this.value = value
        this.children = new Map()
        this.countPerDepth = new Map()
    }
}

class Trie{
    constructor(){
        this.root = new Node("", "")
        this.root.countPerDepth.set(0, 1)
    }

    add(string){
        let node = this.root
        Array.from(string).forEach(c=>{
            // count
            const depthLeft = string.length - node.value.length
            if(!node.countPerDepth.has(depthLeft))
                node.countPerDepth.set(depthLeft, 1)
            else
                node.countPerDepth.set(depthLeft, node.countPerDepth.get(depthLeft)+1)

            if(!node.children.has(c)){
                node.children.set(c, new Node(c, node.value+c))
            }
            node = node.children.get(c)
        })
        node.countPerDepth.set(0, 1)
    }

    searchAmount(string){
        const word = string.replaceAll('?', '')
        const depthLeft = string.length - word.length

        let node = this.root
        for(let i=0; i<word.length; i++){
            if(!node.children.has(word[i])) return 0
            node = node.children.get(word[i])
        }
        if(node.countPerDepth.has(depthLeft))
            return node.countPerDepth.get(depthLeft)
        else return 0
    }
}

// 1명부터 dist.length명까지 완탐
// weak의 id = weak[i]%n

function solution(n, weak, dist) {
    const isCovered = new Map()
    const weakN = weak.length
    weak.forEach((v)=>isCovered[v] = false)
    weak.forEach(v=>weak.push(v+n))

    let answer = -1

    dist.sort((a,b)=>b-a)
    dfs(0, 0)

    return answer

    function dfs(depth, coveredN){
        if(answer!=-1 && depth >= answer) return
        if(coveredN == weakN) 
            return answer = depth
        if(depth == dist.length) return

        const length = dist[depth]
        for(let st=0; st<weakN; st++){
            if(getCovered(st)) continue
            cover(st)

            // covers st~st+l
            let l = 0
            let end = st+1
            let covered = 1
            while(end<weak.length &&
                  !getCovered(end) &&
                  l + weak[end]-weak[end-1] <= length
                 ){
                l += weak[end]-weak[end-1]
                cover(end)
                covered ++
                end++
            }
            dfs(depth+1, coveredN+covered)
            for(let i=st; i<end; i++){
                uncover(i)
            }
        }
    }

    function getCovered(i){
        const location = weak[i]
        return isCovered[location%n]
    }

    function cover(i){
        const location = weak[i]
        isCovered[location%n]=true
    }

    function uncover(i){
        const location = weak[i]
        isCovered[location%n]=false
    }
}

function solution(board) {
    var answer = 0;
    var N = board.length
    var board_ = Array(N+2).fill(0).map((v)=>Array(N+2).fill(1))

    for(let i=1; i<N+1; i++){
        for(let j=1; j<N+1; j++){
            board_[i][j] = board[i-1][j-1]
        }
    }

    // BFS (8가지 경우)
    let visited = Array(N+2).fill(0)
        .map((v)=>Array(N+2).fill(0)
             .map(v=>Array(4).fill(false)
         )
    )
    // [y][x][dir]

    // 하 우 상 좌
    let dirs = [[1, 0], [0, 1], [-1, 0], [0, -1]]
    let branches = [[{
        y:1,
        x:1,
        dir:1,
        depth:0
    }], []]
    let turn = 0

    while(!!branches[0].length || !!branches[1].length){
        while(branches[turn].length>0){
            let next_turn = (turn+1)%2
            let branch = branches[turn].pop()

            let sub_y = branch.y + dirs[branch.dir][0]
            let sub_x = branch.x + dirs[branch.dir][1]

            if((branch.y==N && branch.x==N)
                || (sub_y==N && sub_x==N))
                return branch.depth

            // 무빙
            dirs.forEach(([dy, dx])=>{
                let ny = branch.y + dy
                let nx = branch.x + dx
                let ny2 = branch.y + dy + dirs[branch.dir][0]
                let nx2 = branch.x + dx + dirs[branch.dir][1]
                if(board_[ny][nx]==1 || board_[ny2][nx2]==1) return
                if(visited[ny][nx][branch.dir]) return
                visited[ny][nx][branch.dir] = true
                branches[next_turn].push({
                    y:ny,
                    x:nx,
                    dir:branch.dir,
                    depth:branch.depth+1
                })
            })

            // 회전
            // 메인축
            // 시계방향
            let new_dir = branch.dir==0?3:branch.dir-1
            let new_sub_y = branch.y + dirs[new_dir][0]
            let new_sub_x = branch.x + dirs[new_dir][1]
            let diagonal = board_[branch.y + dirs[branch.dir][0] + dirs[new_dir][0]][branch.x + dirs[branch.dir][1] + dirs[new_dir][1]]
            if(board_[new_sub_y][new_sub_x]!=1
                && diagonal!=1
                && !visited[branch.y][branch.x][new_dir]){
                visited[branch.y][branch.x][new_dir] = true
                branches[next_turn].push({
                    ...branch,
                    dir: new_dir,
                    depth: branch.depth+1
                })
            }
            // 반시계방향
            new_dir = branch.dir==3?0:branch.dir+1
            new_sub_y = branch.y + dirs[new_dir][0]
            new_sub_x = branch.x + dirs[new_dir][1]
            diagonal = board_[branch.y + dirs[branch.dir][0] + dirs[new_dir][0]][branch.x + dirs[branch.dir][1] + dirs[new_dir][1]]

            if(board_[new_sub_y][new_sub_x]!=1
               && diagonal!=1
               && !visited[branch.y][branch.x][new_dir]){
                visited[branch.y][branch.x][new_dir] = true
                branches[next_turn].push({
                    ...branch,
                    dir: new_dir,
                    depth: branch.depth+1
                })
            }

            // 서브축
            // 시계방향
            new_dir = branch.dir==0?3:branch.dir-1
            let new_y = branch.y + dirs[branch.dir][0] - dirs[new_dir][0]
            let new_x = branch.x + dirs[branch.dir][1] - dirs[new_dir][1]
            diagonal = board_[branch.y - dirs[new_dir][0]][branch.x - dirs[new_dir][1]]

            if(board_[new_y][new_x]!=1
               && diagonal!=1
               && !visited[new_y][new_x][new_dir]){
                visited[new_y][new_x][new_dir] = true
                branches[next_turn].push({
                    y: new_y,
                    x: new_x,
                    dir: new_dir,
                    depth: branch.depth+1
                })
            }

            // 반시계방향
            new_dir = branch.dir==3?0:branch.dir+1
            new_y = branch.y + dirs[branch.dir][0] - dirs[new_dir][0]
            new_x = branch.x + dirs[branch.dir][1] - dirs[new_dir][1]
            diagonal = board_[branch.y - dirs[new_dir][0]][branch.x - dirs[new_dir][1]]

            if(board_[new_y][new_x]!=1
               && diagonal!=1
               && !visited[new_y][new_x][new_dir]){
                visited[new_y][new_x][new_dir] = true
                branches[next_turn].push({
                    y: new_y,
                    x: new_x,
                    dir: new_dir,
                    depth: branch.depth+1
                })
            }
        }

        turn = (turn+1)%2
    }

    return answer;
}

