            } else{
                return this
            }
        }
    }
}

function solution(user_id, banned_id) {
    var banned_set = new Set()

    dfs(0, banned_id, user_id, [])
    return banned_set.size;

    function dfs(index, banned_patterns, users, banned_users){
        if(index>=banned_patterns.length){
            let temp_arr = banned_users.slice().sort()
            banned_set.add(serialize(temp_arr))
            return
        }

        let banned_pattern = banned_patterns[index]
        for(let i=0; i<users.length; i++){
            let user_id = users[i]
            if(!!banned_users.find((u)=>u==user_id)) continue
            if(match(user_id, banned_pattern)){
                banned_users.push(user_id)
                dfs(index+1, banned_patterns, users, banned_users)
                banned_users.pop()
            }
        }
    }

    function match(id, con){
        if(id.length!=con.length) return false
        let length = id.length
        for(let i=0; i<length; i++){
            if(id[i]!=con[i])
                if(id[i]!='*' && con[i]!='*')
                    return false
        }
        return true
    }

    function serialize(id_list){
        return id_list.join('')
    }
}

const MAX_LENGTH = 100_000

function solution(gems) {
    let answer = [0, 0]
    let from = 0
    let minLength = MAX_LENGTH
    const indexes = new Map()
    const kinds = new Set(gems).size

    let prevNode = null
    // 100,000번
    gems.forEach((gem, i)=>{
        if(prevNode?.gem===gem)
            prevNode = prevNode.prev

        const node = {
            gem, 
            index: i, 
            prev: null, 
            next: null
        }

        if(prevNode){
            node.prev = prevNode
            prevNode.next = node
        }


        if(indexes.has(gem)){
            const alreadyExistedNode = indexes.get(gem)
            const {index, prev, next} = alreadyExistedNode
            if(index === from){
                if(next !== null){
                    from = next.index
                    next.prev = null
                } else{
                    from = i
                }
            } else{
                // index !== from 이므로 prev는 항상 존재
                if(next !== null){
                    prev.next = next
                    next.prev = prev
                } else{
                    prev.next = node    
                }
            }
        }

        indexes.set(gem, node)

        if(indexes.size==kinds){
            const length = i-from
            if(length < minLength){
                minLength = length
                answer = [from+1, i+1]
            }
        }

        prevNode = node
    })

    return answer;
}

// bfs dp
function solution(board) { 
    const N = board.length
    const costs = Array.from(
        {length:N}, (v)=>Array.from(
            {length:N}, v=>Array(4).fill(Infinity)))

    const q = [{
        px:0,
        y:0,
        x:0,
        cost:0
    },{
        px:-1,
        y:0,
        x:0,
        cost:0
    }]

    const ds = [[0,1],[1,0],[0,-1],[-1,0]]

    const isValid = (y,x)=> y>=0&&x>=0&&y<N&&x<N&&board[y][x]==0

    while(q.length>0){
        let {px,y,x,cost} = q.shift()
        const fv = px==x
        ds.forEach(([dy, dx], di)=>{
            const ny = y + dy
            const nx = x + dx
            if(!isValid(ny,nx)) return

            const tv = x==nx
            const isCorner = fv!=tv
            const newCost = isCorner?cost+600:cost+100

            if(costs[ny][nx][di]>newCost){
                costs[ny][nx][di]=newCost
                q.push({
                    px:x,
                    y:ny,
                    x:nx,
                    cost:newCost
                })
            }
        })
    }

    return Math.min(...costs[N-1][N-1])
}

// 양 쪽 둘 다, 나보다 작은애가 하나라도 있으면 안 된다.
// 두 측 중 한 측이라도 최솟값이면 통과(답++)

const MIN_VAL = -1_000_000_000
const MAX_VAL = 1_000_000_000

function solution(a) {
    let answer = a.length
    const isMinFrom = {
        left:Array.from(a, v=>false),
        right:Array.from(a, v=>false)
    }

    let tempMin = MAX_VAL
    a.forEach((v, i)=>{
        if(v<tempMin) {
            isMinFrom.left[i]=true
            tempMin = v
        }
    })

    isMinFrom.left[0] = true
    isMinFrom.left[a.length-1] = true

    tempMin = MAX_VAL
    for(let i=a.length-1; i>=0; i--){
        const v = a[i]
        if(v<tempMin) {
            isMinFrom.right[i]=true
            tempMin = v
        } else{
            if(!isMinFrom.left[i]){
                answer--
            }
        }
    }

    return answer;
}

function solution(n, s, a, b, fares) {
    var answer = -1;

    // index화
    a--
    b--
    s--

    // 비용 테이블
    const fareTable = Array(n).fill(0).map(v=>Array(n).fill(-1))
    fares.forEach(([ta, tb, cost])=>{
        ta--
        tb--
        fareTable[ta][tb] = cost
        fareTable[tb][ta] = cost
    })

    // S부터 각 지점 까지의 최저 비용 
    const commonCosts = Array(n).fill(-1)
    const fromACosts = Array(n).fill(-1)
    const fromBCosts = Array(n).fill(-1)

    // 다익스트라
    dijkstra(s, commonCosts)
    dijkstra(a, fromACosts)
    dijkstra(b, fromBCosts)

    commonCosts.forEach((cost, i)=>{
        if(cost == -1) return
        let temp_result = cost

        // i까지 같이 타고 감
        temp_result += fromACosts[i]
        temp_result += fromBCosts[i]

        if(answer==-1 || temp_result<answer) answer = temp_result
    })

    return answer;

    function dijkstra(s, costArray){
        // bfs
        const queue = [[s,0]]
        costArray[s] = 0
        while(queue.length>0){
            const [node, cost] = queue.shift()
            if(cost>costArray[node]) continue

            fareTable[node].forEach((fare, to)=>{
                if(fare==-1) return

                const newCost = cost+fare
                if(costArray[to]>=0 && newCost>=costArray[to]) return
                costArray[to] = newCost
                queue.push([to, newCost])
            })
        }
    }
}

/*
    30만 -> 최대 NlogN
    모든 팀이 참가하면서, 최소가 되는 매출 손실액
    DP
*/

const INFINITE = 2147483647

class Node{
    static nodes = new Map()

    constructor(value){
        this.value = value
        this.children = []
    }

    addChild(child){
        this.children.push(child)
    }
}

function solution(sales, links) {
    const N = sales.length
    var answer = 0;

    const nodes = Node.nodes
    const teams = new Map()

    sales.forEach((v, i)=>{
        nodes.set(i+1, new Node(v));
    })

    links.forEach(([p,c])=>{
        nodes.get(p).addChild(nodes.get(c))
        teams.set(p, nodes.get(p))
    })

    answer = Math.min(...dfs(nodes.get(1)))

    return answer;

    function dfs(node){
        // node의 모든 자식 팀을 워크숍에 보내는 데에 드는 최소비용
        if(node.children.length==0){
            return [0, node.value]
        }

        let cost = 0
        let minDif = Infinity
        let isAllNotGo = true

        node.children.forEach((child)=>{
            const costs = dfs(child)
            cost += Math.min(...costs)
            if(costs[1]>costs[0]){
                const dif = costs[1] - costs[0]
                if(minDif > dif) minDif = dif
            } else{
                isAllNotGo = false
            }
        })

        return [cost + ((isAllNotGo)?minDif:0), cost + node.value]

    }
}

function solution(a, edges){
    // O / X
    let sum = a.reduce((sum, t)=>sum+t, 0)
    if(sum!=0) return -1

    // 횟수
    // make 0 from leaves

    let n = a.length
    let edgeArray = Array(n).fill(0).map(v=>[])

    edges.forEach(([u,v])=>{
        edgeArray[u].push(v)
        edgeArray[v].push(u)
    })

    // root is always 0
    // store parents

    let nodes = [[0, 0]]
    let stack = []

    // BFS
    while(nodes.length>0){
        let [node, parent] = nodes.pop()
        stack.push([node, parent])

        edgeArray[node].forEach(child=>{
            if(child==parent) return
            nodes.push([child, node])
        })
    }

    let answer = 0n

    while(stack.length>0){
        let [node, parent] = stack.pop()
        a[parent] += a[node]
        answer += BigInt(Math.abs(a[node]))
    }

    return answer
}

function solution(enroll, referral, seller, amount) {
    var answer = Array(enroll.length).fill(0);
    let name_index_map = new Map()
    enroll.forEach((name, index)=>{
        name_index_map.set(name, index)
    })
    name_index_map.set('-', -1)

    seller.forEach((name, i)=>{
        makeMoney(name_index_map.get(name), amount[i]*100)
    })

    return answer;

    function makeMoney(index, margin){
        if(index==-1) return

        let passOver = Number.parseInt(margin/10)
        answer[index] += margin-passOver

        if(passOver==0) return

        makeMoney(name_index_map.get(referral[index]), passOver)
    }
}

