    #각 빈칸을 최소 크기로 변환
    # 0으로만 이루어진 행 제거
    for shape in holes:
        i=0
        while i < len(shape):
            if shape[i].count(1)==0:
                shape.pop(i)
                continue
            i += 1


    # 0으로만 이루어진 열 제거
    for shape in holes:
        i=0
        while i < len(shape[0]):
            found = 0 # 1을 찾았는가?
            for j in range(len(shape)): # j번 [y]에서 i번 x가 ..
                if shape[j][i]:
                    found = 1
                    break
            if found: # 1이 있다.
                i += 1
                continue
            for puzzle in shape: # 모든 y에서 i번 줄을 삭제하자.
                puzzle.pop(i)

    #퍼즐 모양을 회전시켜 4배로 저장하기
    newPuzzles = []
    for puzzle in puzzles:
        newPuzzles.append(puzzle)
        for i in range(3):
            newPuzzles.append(rotate(newPuzzles[-1]))

    #모양과 빈칸을 비교하기
    answer = 0
    found = 0
    for i in range(0, len(newPuzzles), 4):
        for hole in holes:
            for j in range(4):
                if newPuzzles[i+j] == hole:
                    found = 1
                    holes.pop(holes.index(hole))
                    answer += getSize(newPuzzles[i+j])
                    break
            if found:
                break
        found = 0
    return answer

function solution(grid) {
    let answer = []

    const H = grid.length
    const W = grid[0].length
    const board = Array(H).fill(0).map((v, i)=>grid[i].split(""))
    const visited = Array(H).fill(0).map((_)=>Array(W).fill(0).map((__)=>Array(4).fill(0)))
    let visitIndex = 0
    const ds = [[-1, 0], [0, 1], [1, 0], [0, -1]]

    for(let y=0; y<H; y++){
        for(let x=0; x<W; x++){
            ds.forEach((d, di)=>{
                visited[y][x][di] = checkCycle(y, x, di)
            })
        }
    }

    return answer.sort((a, b)=>a-b)

    function checkCycle(y, x, di){
        visitIndex++
        if(visited[y][x][di]>0){
            return false
        }

        let ny = y + ds[di][0]
        let nx = x + ds[di][1]

        if(ny<0) ny = H-1
        else if(ny>=H) ny = 0
        if(nx<0) nx = W-1
        else if(nx>=W) nx = 0

        let ndi = getNdi(di, ny, nx)

        let length = 1

        while(ny!==y || nx!==x || ndi!==di){
            length++

            if(visited[ny][nx][ndi]>0 && visited[ny][nx][ndi]!=visitIndex){
                return false
            }
            visited[ny][nx][ndi] = visitIndex

            ny += ds[ndi][0]
            nx += ds[ndi][1]
            if(ny<0) ny = H-1
            else if(ny>=H) ny = 0
            if(nx<0) nx = W-1
            else if(nx>=W) nx = 0

            ndi = getNdi(ndi, ny, nx)
        }

        answer.push(length)

        return true
    }

    function getNdi(di, ny, nx){
        const type = board[ny][nx]
        if(type=='R'){
            return (di+1)%4
        } else if(type=='L'){
            return (di+3)%4
        } else if(type=='S'){
            return di
        }
    }
}

'''
    점마다 이동가능한지 테이블 유지
    50x50 테이블 유지
    0: 이동 불가. 초기값.
    1: 이동 가능.
    2: 이동 불가, 변경 불가: 직사각형 내부를 의미.
    1, 2는 직사각형 배열을 돌면서 추가.
'''
from collections import deque
def solution(rectangle, characterX, characterY, itemX, itemY):
    answer = 0
    mapTable = [[0 for _ in range(51*2)] for __ in range(51*2)]
    for r in rectangle:
        x1, y1, x2, y2 = r
        x1 *= 2
        x2 *= 2
        y1 *= 2
        y2 *= 2
        for x in range(x1, x2+1):
            if mapTable[y1][x] != 2:
                mapTable[y1][x] = 1
            if mapTable[y2][x] != 2:
                mapTable[y2][x] = 1
        for y in range(y1, y2+1):
            if mapTable[y][x1] != 2:
                mapTable[y][x1] = 1
            if mapTable[y][x2] != 2:
                mapTable[y][x2] = 1
        for y in range(y1+1, y2):
            for x in range(x1+1, x2):
                mapTable[y][x] = 2

    #BFS
    q = deque([(characterX*2, characterY*2, 1)])
    while q:
        x, y, cost = q.popleft()
        if (x==itemX*2) and (y==itemY*2):
            return int(cost/2)
        mapTable[y][x] = 2
        if mapTable[y][x-1]==1:
            q.append((x-1, y, cost+1))
        if mapTable[y][x+1]==1:
            q.append((x+1, y, cost+1))
        if mapTable[y-1][x]==1:
            q.append((x, y-1, cost+1))
        if mapTable[y+1][x]==1:
            q.append((x, y+1, cost+1))

    return answer

