            if renewK(newArr, kG) >= 0:
                getPath(newArr, i+1)
        if len(arr) == 0:
            if renewK([dungeonsG[i]], kG) >= 0:
                getPath([dungeonsG[i]], i+1)
    else:
        amounts.append(len(arr))


