function dijkstra(st, costs){
  const q = [[st, 0]]
  let qi = 0
  while(qi<q.length){
    const [cn, cc] = q[qi++]
    
    if(costs[cn] < cc) continue
    costs[cn] = cc

    for(let i=0; i<edges[cn].length; i++){
      const [nn, nc] = edges[cn][i]
      if(costs[nn] <= cc + nc) continue
      q.push([nn, cc + nc])
      costs[nn] = cc + nc
    }
  }
}

