function binarySearch(n){
  // n을 tempArr에 넣기
  let l = 0
  let r = tempArr.length-1
  let mid = l
  while(l+1<r){
    mid = Math.floor((l+r+1)/2)
  
    if(tempArr[mid]<n){ // go right
      l = mid
    } else{ // go left
      r = mid
    }
  }

  while(tempArr[mid]<n)mid++
  while(tempArr[mid-1]>n)mid--

  return mid
}

