function getSize(y, x){
    // 내 주변 getSize를 리턴
    if(floorMap[y][x]==0) return 0
    let res = 1
    floorMap[y][x] = 0

    if(y>0) res+=getSize(y-1, x)
    if(x>0) res+=getSize(y, x-1)
    if(y<H-1) res+=getSize(y+1, x)
    if(x<W-1) res+=getSize(y, x+1)
    return res
}

