class Main{
  public static void main(String[] args)throws IOException{
    BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
    int n = Integer.parseInt(br.readLine());
    // dp[i] : 전깃줄이 i까지 내려왔을 때 킬 수 있는 최대 전구 수
    int[] switches = new int[n];
    int[] switchLocs = new int[n];
    int[] bulbLocs = new int[n];
    int[] bulbs = new int[n];

    StringTokenizer st = new StringTokenizer(br.readLine());

    int number;
    for(int i=0; i<n; i++){
      // i번째 스위치의 번호는 number다
      number = Integer.parseInt(st.nextToken())-1;
      switches[i] = number;
      // number번 스위치는 i에 있다.
      switchLocs[number] = i;
    }

    // switch 번호로 전구 위치를 찾아갈 수 있어야 함.
    // switches[i]에 i를 담기
    st = new StringTokenizer(br.readLine());
    for(int i=0; i<n; i++){
      // 이 전구에 연결되는 스위치의 전구는 i번째에 있다.
      number = Integer.parseInt(st.nextToken())-1;
      bulbLocs[number] = i;
      bulbs[i] = number;
    }
    
    int[] dp = new int[n];
    int res = 0;
    int resIdx = -1;
    int from, to, maxBulbs, idx;
    int[] indexes = new int[n]; // 역추적
    for(int i=0; i<n; i++) indexes[i] = -1;
    for(int i=0; i<n; i++){
      from = i;
      to = bulbLocs[switches[i]]; // i번째 스위치의 번호와 같은 번호의 전구의 위치
      maxBulbs = 0;
      idx = -1;
      for(int j=0; j<to; j++){
        if(dp[j]>maxBulbs){
          maxBulbs = dp[j];
          idx = j;
        }
      }
      dp[to] = maxBulbs+1;
      indexes[to] = idx;
      if(dp[to]>res){
        res = dp[to];
        resIdx = to;
      }
    }
    ArrayList<Integer> resArr = new ArrayList<>();
    from = resIdx;
    while(from!=-1){
      resArr.add(bulbs[from]+1);
      from = indexes[from];
    }
    Collections.sort(resArr);
    System.out.println(res);
    StringBuilder sb = new StringBuilder();
    for(int i=0; i<resArr.size(); i++){
      sb.append(resArr.get(i) + " ");
    }
    System.out.println(sb.toString().trim());

    // int maxTemp = 0;
    // ArrayList<Integer> res = new ArrayList<>();
    // for(int i=0; i<n; i++){
    //   if(dp[i]>maxTemp) {
    //     res.add(bulbs[i]+1);
    //     maxTemp = dp[i];
    //   }
    // }
    // System.out.println(maxTemp);
    // Collections.sort(res);
  }
}

import java.io.*;
import java.util.*;

class Main{
  static long res = 0, N;
  static long[] usedCubes = new long[20];
  static int[] cubes = new int[20];
  public static void main(String[] args) throws IOException{
    BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
    StringTokenizer st = new StringTokenizer(br.readLine());

    int l, w, h;
    l = Integer.parseInt(st.nextToken());
    w = Integer.parseInt(st.nextToken());
    h = Integer.parseInt(st.nextToken());
    N = Integer.parseInt(br.readLine());

    int size, amount;


    for(int i=0; i<N; i++){
      st = new StringTokenizer(br.readLine());
      size = Integer.parseInt(st.nextToken());
      amount = Integer.parseInt(st.nextToken());

      if(amount==0) continue;

      cubes[size] = amount;
    }

    fill(l, w, h);
    useCubes();
    System.out.println(res);
  }

  static void useCubes(){
    for(int i=19; i>=0; i--){
      if(usedCubes[i]>cubes[i]){
        if(i==0) {res = -1; return;}
        usedCubes[i-1] += (usedCubes[i]-cubes[i])*8; // 더 작은 큐브로 채워보기
        usedCubes[i] = cubes[i];
      }
      res += usedCubes[i];
    }
  }

  static void fill(int l, int w, int h){
    if(l==0 || w==0 || h==0) return;

    int minL = (int) Math.min(l, Math.min(w, h));
    int i = log2(minL);
    int size = (int)Math.pow(2, i);

    int[] counts = new int[3];
    counts[0] = l/size;
    counts[1] = w/size;
    counts[2] = h/size;
    
    // size로 최대한 채우기
    usedCubes[i] += (long)counts[0]*(long)counts[1]*(long)counts[2];

    // 남은 공간에 대해서 dfs
    // 3개의 육면체에 대한 fill 호출
    if(w-size>0)
      fill(l, w-(size*counts[1]), h);
    if(h-size>0)
      fill(l, size*counts[1], h-(size*counts[2]));
    if(l-size>0)
      fill(l-(size*counts[0]), size*counts[1], size*counts[2]);
  }

  static int log2(int n){
    return (int)(Math.log(n)/Math.log(2));
  }
}

import java.io.*;
import java.util.*;

public class Main{
    static int H, W;
    static int[][] map;
    static int[][] air;
    static int cheese;
    static ArrayDeque<int[]> toMelt;
    static int[][] dirs = {{1, 0}, {0, 1}, {-1, 0}, {0, -1}};
    public static void main(String[] args) throws IOException{
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        H = Integer.parseInt(st.nextToken());
        W = Integer.parseInt(st.nextToken());
        map = new int[H][W];
        air = new int[H][W];
        cheese = 0;

        toMelt = new ArrayDeque<>();
        ArrayDeque<int[]> temp = new ArrayDeque<>();

        int ny, nx;
        for(int i=0; i<H; i++){
            st = new StringTokenizer(br.readLine());
            for(int j=0; j<W; j++){
                map[i][j] = Integer.parseInt(st.nextToken());
                if(map[i][j]==1) cheese ++;
            }
        }

        map[0][0] = 2;
        floodFill(0, 0, toMelt);

        int res = 0;
        while(cheese>0){
            ++res;
            cheese -= toMelt.size();

            temp = new ArrayDeque<>();
            while(!toMelt.isEmpty()){
                int[] yx = toMelt.poll();
                if(map[yx[0]][yx[1]] != 1) continue;
                map[yx[0]][yx[1]] = 2;
                floodFill(yx[0], yx[1], temp); // temp에 다음 녹을 치즈를 넣음
            }
            toMelt = temp;
        }

        System.out.println(res);
    }

    static public void floodFill(int y, int x, ArrayDeque<int[]> temp){
        int ny, nx;
        for(int[] dir: dirs){
            ny = y+dir[0];
            nx = x+dir[1];
            if(ny<0||nx<0||ny>=H||nx>=W) continue;
            if(map[ny][nx]==1){
                if(++air[ny][nx]==2)
                    temp.add(new int[]{ny, nx});
            } else if(map[ny][nx] == 0){
                map[ny][nx] = 2;
                floodFill(ny, nx, temp);
            }
        }
    }

}

/*
 * 
 * 경로의 개수
 * DP 혹은 DFS 완전탐색
 * 
 * 세로 M 가로 N
 * 
 * DP
 * DP[i][j] : (i, j)에서 (M-1, N-1)까지 갈 수 있는 경로의 수
 * 초깃값:
 * DP[M-1][N-1] = 1
 * 

4 5
50 45 37 32 30
35 50 40 20 25
30 30 25 17 28
27 24 22 15 10

> 3

 * 
 */

import java.io.*;
import java.util.*;

public class Main {
    static int[][] map;
    static int[][] dp;
    static int H, W;
    public static void main(String[] args) throws IOException{
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        H = Integer.parseInt(st.nextToken());
        W = Integer.parseInt(st.nextToken());
        map = new int[H][W];
        dp = new int[H][W];

        for(int i=0; i<H; i++) Arrays.fill(dp[i], -1);
        dp[H-1][W-1] = 1;

        for(int i=0; i<H; i++){
            st = new StringTokenizer(br.readLine());
            for(int j=0; j<W; j++) map[i][j] = Integer.parseInt(st.nextToken());
        }

        dfs(0, 0);
        
        System.out.println(dp[0][0]);
    }

    static int[][] dirs = {{1, 0}, {0, 1}, {-1, 0}, {0, -1}};

    public static int dfs(int y, int x){
        if(dp[y][x]!=-1) return dp[y][x];

        int paths = 0;

        for(int[] dir: dirs){
            int ny = y + dir[0];
            int nx = x + dir[1];

            if(ny<0 || nx<0 || ny>=H || nx>=W) continue;
            if(map[ny][nx]>=map[y][x]) continue;
            paths += dfs(ny, nx);
        }
        dp[y][x] = paths;
        return paths;
    }
}

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.ArrayDeque;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collections;
import java.util.StringTokenizer;

public class Main {
    public static void main(String[] args) throws IOException{
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int N = Integer.parseInt(br.readLine());
        int[] numbers = new int[N];
        int[] indexes = new int[N];
        ArrayList<Integer> LIS = new ArrayList<>();

        StringTokenizer st = new StringTokenizer(br.readLine());
        for(int i=0; i<N; i++){
            numbers[i] = Integer.parseInt(st.nextToken());
        }

        for(int i=0; i<N; i++){
            int idx = (-Collections.binarySearch(LIS, numbers[i]) -1);
            // System.out.println(idx);
            // System.out.println("idx:" + idx + ", LIS.size(): " + LIS.size());
            if(idx<0) {
                indexes[i] = -idx-1;
            } else if(idx>= LIS.size()){
                indexes[i] = LIS.size();
                LIS.add(numbers[i]);
            } else{
                indexes[i] = idx;
                LIS.set(idx, numbers[i]);
            }
        }

        // System.out.println(LIS);
        // System.out.println(Arrays.toString(indexes));
        int curIdx = LIS.size()-1;
        ArrayDeque<Integer> stack = new ArrayDeque<>(); 
        for(int i=N-1; i>=0; i--){
            if(indexes[i] == curIdx){
                curIdx--;
                stack.addFirst(numbers[i]);
                if(curIdx==-1) break;
            }
        }
        StringBuilder sb = new StringBuilder();
        sb.append(LIS.size()).append("\n");
        while(!stack.isEmpty())sb.append(stack.pop() + " ");
        System.out.println(sb.toString().trim());
    }
}

