public class Main {

	public static void main(String[] args) throws IOException{
		BufferedReader br = new BufferedReader(new InputStreamReader(System.in)); 
		char[] str = br.readLine().toCharArray();
		int n = str.length;
		int res = 0;
		for (int k = 0; k < n-1; k++) { // 비교 패턴 문자열 시작 인덱스
			int j = k, i=k+1;
