/*

7
WINNT\SYSTEM32\CONFIG
GAMES
WINNT\DRIVERS
HOME
WIN\SOFT
GAMES\DRIVERS
WINNT\SYSTEM32\CERTSRV\CERTCO~1\X86

GAMES
 DRIVERS
HOME
WIN
 SOFT
WINNT
 DRIVERS
 SYSTEM32
  CERTSRV
   CERTCO~1
    X86
  CONFIG

 */

public class Main {
	static BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
	static StringBuilder sb = new StringBuilder();
	
	static class Node implements Comparable<Node>{
		String value;
		TreeSet<Node> children = new TreeSet<>();
		Node(){}
		Node(String value){
			this.value = value;
		}
		void addChild(Node node) {
			children.add(node);
		}
		@Override
		public int compareTo(Node o) {
			return value.compareTo(o.value);
		}
	}
	public static void main(String[] args) throws IOException{
		int N = Integer.parseInt(br.readLine());
		Node root = new Node();
		for (int i = 0; i < N; i++) {
			Node prev = root;
			StringTokenizer st = new StringTokenizer(br.readLine(), "\\");
			while(st.hasMoreTokens()) {
				String tmp = st.nextToken();
				Node node = new Node(tmp);
				if(!prev.children.contains(node)) {
					prev.addChild(node);
				} else {
					node = prev.children.ceiling(node);
				}
				prev = node;
			}
		}
		
		dfs(root, 0);
		System.out.println(sb.toString());
	}
	private static void dfs(Node node, int depth) {
		if(depth>0) {
			for (int i = 0; i < depth-1; i++) {
				sb.append(' ');
			}
			sb.append(node.value).append('\n');
		}
		for(Node child:node.children) {
			dfs(child, depth+1);
		}
	}

}

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.StringTokenizer;

/*

4
0 10 15 20
5 0 9 10
6 13 0 12
8 8 9 0

 */

public class Main {
    static BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
    static int[][] dp, costs;
    static int n;
    
    static final int MAX_VALUE = 16000000;
    
    public static void main(String[] args) throws IOException{
        n = Integer.parseInt(br.readLine()); // <= 16
        dp = new int[n][1<<n];
        costs = new int[n][n];
        for (int i = 0; i < n; i++) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            for (int j = 0; j < n; j++)
                costs[i][j] = Integer.parseInt(st.nextToken());
        }
        
        System.out.println(dfs(0, 1)); // returns dp[0][1]
        // dp[i][visit] : 	visit만큼 방문한 상태에서,
        //					i번 노드로부터 탐색을 시작할 때 가능한 최소 순회 비용 
        
//        for (int i = 0; i < n; i++) {
//            System.out.println(Arrays.toString(dp[i]));
//        }
    }

    public static int dfs(int cur, int visit) {
        if(visit == (1<<n)-1) {
            if(costs[cur][0]>0) return costs[cur][0];
            else return MAX_VALUE;
        }
        
        if(dp[cur][visit]>0) return dp[cur][visit]; // 갱신한 적이 있음.
        
        dp[cur][visit] = MAX_VALUE;
        for (int i = 0; i < n; i++) {
            if((visit & (1<<i))>0 || costs[cur][i]==0) continue;
            dp[cur][visit] = Math.min(dp[cur][visit], costs[cur][i] + dfs(i, visit|(1<<i)));
        }
//        System.out.println("DP: " + dp[cur][visit]);
        return dp[cur][visit];
    }
}

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.HashMap;
import java.util.StringTokenizer;

public class Main {
	static long P, Q;
	static HashMap<Long, Long> valuePool = new HashMap<>();
	public static void main(String[] args) throws IOException{
		BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
		StringTokenizer st = new StringTokenizer(br.readLine());
		long i = Long.parseLong(st.nextToken());
		P = Integer.parseInt(st.nextToken());
		Q = Integer.parseInt(st.nextToken());
		
		System.out.println(getRes(i));
	}
	
	public static long getRes(long n) {
		if(n<=0) return 1;
		if(!valuePool.containsKey(n)) valuePool.put(n, getRes((long)(n/P)) + getRes((long)(n/Q)));
		return valuePool.get(n);
		
	}
}

import java.io.*;
import java.util.*;

public class Main {

	public static void main(String[] args) throws IOException{
		BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
		StringTokenizer st = new StringTokenizer(br.readLine());
		int N = Integer.parseInt(st.nextToken());
		int M = Integer.parseInt(st.nextToken());
		int costSum=0;

		int[] memories = new int[N];
		int[] costs = new int[N];
		
		// memory
		st = new StringTokenizer(br.readLine());
		for(int i=0; i<N; i++) {
			int m = Integer.parseInt(st.nextToken());
			memories[i] = m;
		}
		
		// cost
		st = new StringTokenizer(br.readLine());
		for(int i=0; i<N; i++) {
			int cost = Integer.parseInt(st.nextToken());
			costs[i] = cost;
			costSum += cost;
		}
		
		int[] dp = new int[costSum+1]; // dp[i] : i비용으로 확보할 수 있는 최대 memory
		
		for(int i=0; i<N; i++) {
			for(int j=costSum; j>=costs[i]; j--) {
				// i번째 앱을 종료하는게 더 크다!
				if(dp[j-costs[i]] + memories[i] > dp[j]) dp[j] = dp[j-costs[i]] + memories[i]; 
			}
//			System.out.println(Arrays.toString(dp));
		}
		
		
		for(int i=0; i<=costSum; i++) {
			if(dp[i]>=M) {
				System.out.print(i);
				break;
			}
		}
	}

}

