import java.io.*;
import java.util.*;

public class Main {

	public static void main(String[] args) throws IOException{
		BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
		int N = Integer.parseInt(br.readLine());
		int[][] dp = new int[2][N+1];
		dp[0][0] = 0; // 지우지 않은 경우
		dp[1][0] = 0; // 하나 지운 경우
		StringTokenizer st = new StringTokenizer(br.readLine());
		int res = -1000;
		
		int number = Integer.parseInt(st.nextToken());
		dp[0][1] = number;
		dp[1][1] = 0;
		
		res = number;
		
		for(int i=2; i<=N; i++) {
			number = Integer.parseInt(st.nextToken());
			
			boolean restarted = false;
			
			// 이어서 추가하기
			dp[0][i] = dp[0][i-1] + number;
			// 새로 시작
			if(dp[0][i] < number) {
				dp[0][i] = number;
				restarted = true;
			}
			
			if(dp[0][i] > res) res = dp[0][i];
			
			// 이어서 추가하기
			dp[1][i] = dp[1][i-1] + number;
			// 지금껄 빼서 대체하기 -> 새로 시작한걸 빼면 개수가 0이 됨 
			if(dp[1][i]<dp[0][i] - number && !restarted) dp[1][i] = dp[0][i] - number;
			
			if(dp[1][i] > res) res = dp[1][i];
		}

//		System.out.println(Arrays.toString(dp[0]));
//		System.out.println(Arrays.toString(dp[1]));
		
		System.out.println(res);
	}

}

import java.io.*;
import java.util.*;

public class Main {

	public static void main(String[] args) throws IOException{
		// 병합정렬처럼 작동하기
		// 3개를 봐서 1,2를 합칠지 2,3을 합칠지
		BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
		int n = Integer.parseInt(br.readLine());
		
		StringTokenizer st;
		int[][] matrix = new int[n][2];
		for(int i=0; i<n; i++) {
			st = new StringTokenizer(br.readLine());
			int r = Integer.parseInt(st.nextToken());
			int c = Integer.parseInt(st.nextToken());
			
			matrix[i][0] = r;
			matrix[i][1] = c;
		}
		int[][] dp = new int[n][n]; // i~j를 합쳤을 때 최소 연산 횟수 
		
		for(int i=0; i<n; i++)
			for(int j=0; j<n; j++) dp[i][j] = Integer.MAX_VALUE;
		
		for(int i=0; i<n; i++) dp[i][i] = 0;

		for(int len=1; len<n; len++) {
			for(int l=0; l<n-len; l++) {
				int r= l + len;
				for(int m= l; m<r; m++) {
					dp[l][r] = Math.min(dp[l][r], dp[l][m] + dp[m+1][r] + matrix[l][0]*matrix[m][1]*matrix[r][1]);
				}
			}
		}
		System.out.println(dp[0][n-1]);
	}
}

import java.io.*;

public class Main {

	public static void main(String[] args) throws IOException{
		BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
		int T = Integer.parseInt(br.readLine());
		for(int tc = 0; tc<T; tc++) {
			int n = Integer.parseInt(br.readLine());
			int[] dp = new int[n+1];
			dp[0] = 1;
			dp[1] = 1;
			for(int i=2; i<n+1; i++) {
				for(int j=1; j<=i; j++) {
					if(i-j >= 0)
						dp[i] += dp[i-j]*getMult(j); 
				}
			}
			
			System.out.println(dp[n]);
		}
	}
	
	public static int getMult(int j) {
		if(j==1) return 1;
		else if(j==2) return 4;
		else if(j%2==0) return 3;
		else return 2;
	}
}

import java.io.*;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.HashMap;
import java.util.Map.Entry;
import java.util.StringTokenizer;

public class Main {

	public static void main(String[] args) throws IOException{
		BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
		StringTokenizer st = new StringTokenizer(br.readLine());
		int N = Integer.parseInt(st.nextToken()); // <= 100
		int K = Integer.parseInt(st.nextToken()); // <= 100000
		int[][] stuff = new int[N][2];
		for (int i = 0; i < N; i++) {
			st = new StringTokenizer(br.readLine());
			int w = Integer.parseInt(st.nextToken());
			int v = Integer.parseInt(st.nextToken());
			stuff[i][0] = w;
			stuff[i][1] = v;
		}
		
		// 보석 도둑과 다른 점: 가방이 하나다.
		
//		int[] dp =new int[K+1]; // dp[i]: i의 무게로 담을 수 있는 최대 가치
		HashMap<Integer, Integer> weightValue = new HashMap<>();
		int maxV = 0;
		for (int i = 0; i < N; i++) {
			int w = stuff[i][0];
			int v = stuff[i][1];
			
			ArrayList<int[]> newEntries = new ArrayList<>();
			
			for(Entry<Integer, Integer> wv : weightValue.entrySet()) {
				int newV = v+wv.getValue();
				int newW = w+wv.getKey();
				
				if(K >= newW && (!weightValue.containsKey(newW) || weightValue.get(newW) < newV)) {
					newEntries.add(new int[] {newW, newV});
					if(newV > maxV) maxV = newV;
				}
			}
			
			for(int[] entry: newEntries) {
				weightValue.put(entry[0], entry[1]);
			}

			if(K >= w && (!weightValue.containsKey(w) || weightValue.get(w) < v)) {
				weightValue.put(w, v);
				if(v > maxV) maxV = v;
			}
		}
//		System.out.println(weightValue);
		System.out.println(maxV);
	}

}

