import java.util.StringTokenizer;

/*
 * 
 * 실행시간 76ms
 * 메모리 13204kb
 * 
4
0 10 15 20
5 0 9 10
6 13 0 12
8 8 9 0
 */

public class Main {
	static int N, res = 10000000;
	static int[] numbers;
	static int[][] edges;
	static BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
	public static void main(String[] args) throws IOException{
		StringTokenizer st;
		// 간선 입력 받기
		N = Integer.parseInt(br.readLine());
		edges = new int[N][N];
		numbers = new int[N];
		for (int i = 0; i < N; i++) {
			numbers[i] = i;
			st = new StringTokenizer(br.readLine());
			for (int j = 0; j < N; j++) {
				edges[i][j] = Integer.parseInt(st.nextToken());
			}
		}
		
		// 순열
		numbers[0] = 0;
		permutation(1, 0);
		
		System.out.println(res);
	}
	
	public static void permutation(int depth, int cost) {
		if(cost >= res) return;
		if(depth == N-1) {
			int w = edges[numbers[N-2]][numbers[N-1]];
			if(w==0) return;
			if(edges[numbers[N-1]][0]==0) return;
			cost += w + edges[numbers[N-1]][numbers[0]];
			
			// 가능하다면 비용 비교
			if(res > cost) res = cost;
			return;
		}
		
		for (int i = depth; i < N; i++) {
			if(edges[numbers[depth-1]][numbers[i]]==0) continue;
			// depth=>i 연결
			swap(i, depth);
			permutation(depth+1, cost + edges[numbers[depth-1]][numbers[depth]]);
			swap(i, depth);
		}
	}
	
	public static void swap(int a, int b) {
		int temp = numbers[a];
		numbers[a] = numbers[b];
		numbers[b] = temp;
	}
}

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.StringTokenizer;

public class Main {
	static int K;
	static char[] folds;
	static int[][] board;
	public static void main(String[] args) throws IOException{
		BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
		StringBuilder sb = new StringBuilder();
		
		// 입력
		StringTokenizer st;
		K = Integer.parseInt(br.readLine());
		folds = new char[K*2];
		
		st = new StringTokenizer(br.readLine());
		for (int i = 0; i < K*2; i++) {
			folds[i] = st.nextToken().charAt(0);
		}
		
		// 2^k * 2^k int 보드 생성
		int l = (int)Math.pow(2, K);
		board = new int[l][l];
		
		// D: y+, R: x+ => 구멍이 그대로 뚫리는 위치 찾기
		int y=0, x=0, dy=l, dx=l;
		for (int i = 0; i < K*2; i++) {
			switch (folds[i]) {
			case 'D':
				dy /= 2;
				y += dy;
				break;
			case 'R':
				dx /= 2;
				x += dx;
				break;
			case 'U':
				dy /= 2;
				break;
			case 'L':
				dx /= 2;
				break;
			default:
				System.out.println("FOLDS ERR: 46");
				break;
			}
		}
		
		// 해당 위치 구멍을 input으로 설정.
		board[y][x] = Integer.parseInt(br.readLine());
		
		// 대칭점 구멍 설정을 반복 (K*2번)
		int h=1, w=1;
		for (int i = K*2-1; i >= 0; i--) {
			// 접은거의 역순, 시작좌표 얻기
			switch (folds[i]) {
			case 'D': // 위로 펴기
				for (int ty = y; ty < y+h; ty++) {
					for (int tx = x; tx < x+w; tx++) {
						// 대칭찍기
						if(h==1) board[ty-h][tx] = flipY(board[ty][tx]);
						else board[ty-h][tx] = board[ty][tx];
					}
				}
				y-=h;
				h*=2;
				break;
			case 'U': // 아래로 펴기
				for (int ty = y; ty < y+h; ty++) {
					for (int tx = x; tx < x+w; tx++) {
						// 대칭찍기
						if(h==1) board[ty+h][tx] = flipY(board[ty][tx]);
						else board[ty+h][tx] = board[ty][tx];
					}
				}
				h*=2;
				break;
			case 'R': // 왼쪽으로 펴기
				for (int ty = y; ty < y+h; ty++) {
					for (int tx = x; tx < x+w; tx++) {
						// 대칭찍기
						if(w==1) board[ty][tx-w] = flipX(board[ty][tx]);
						else board[ty][tx-w] = board[ty][tx];
					}
				}
				x-=w;
				w*=2;
				break;
			case 'L': // 오른쪽으로 펴기
				for (int ty = y; ty < y+h; ty++) {
					for (int tx = x; tx < x+w; tx++) {
						// 대칭찍기
						if(w==1) board[ty][tx+w] = flipX(board[ty][tx]);
						else board[ty][tx+w] = board[ty][tx];
					}
				}
				w*=2;
				break;
			}
		}
		
		// 답 출력
		for (int i = 0; i < l; i++) {
			for (int j = 0; j < l-1; j++) {
				sb.append(board[i][j]).append(" ");
			}
			sb.append(board[i][l-1]).append('\n');
		}
		System.out.println(sb.toString());
	}
	
	public static int flipY(int prev) {
		switch (prev) {
		case 0:
			return 2;
		case 1:
			return 3;
		case 2:
			return 0;
		case 3:
			return 1;
		}
		System.out.println("flipY err");
		return 0;
	}
	
	public static int flipX(int prev) {
		switch (prev) {
		case 0:
			return 1;
		case 1:
			return 0;
		case 2:
			return 3;
		case 3:
			return 2;
		}
		System.out.println("flipX err");
		return 0;
	}
}

/*
 * 최소신장트리를 구하고, 가중치가 가장 큰 간선을 제거한다.
 */

import java.io.*;
import java.util.Arrays;
import java.util.StringTokenizer;

public class Main {
	static BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
	static int N, E;
	
	static class Edge implements Comparable<Edge>{
		int from, to, cost;
		
		public Edge(int from, int to, int cost) {
			super();
			this.from = from;
			this.to = to;
			this.cost = cost;
		}

		@Override
		public int compareTo(Edge o) {
			return Integer.compare(cost, o.cost);
		}
	}
	
	static int[] parents;
	
	static void make() {
		parents = new int[N];
		for (int i = 0; i < N; i++) {
			parents[i] = i;
		}
	}
	
	static int find(int a) {
		if(parents[a] == a) return a;
		return parents[a] = find(parents[a]);
	}
	
	static boolean union(int a, int b) {
		int ra = find(a);
		int rb = find(b);
		if(ra==rb) return false;
		parents[ra] = rb;
		return true;
	}
	
	public static void main(String[] args) throws IOException{
		StringTokenizer st = new StringTokenizer(br.readLine());
		N = Integer.parseInt(st.nextToken());
		E = Integer.parseInt(st.nextToken());
		Edge[] edges = new Edge[E];
		int from, to, cost;
		for (int i = 0; i < E; i++) {
			st = new StringTokenizer(br.readLine());
			from = Integer.parseInt(st.nextToken())-1;
			to = Integer.parseInt(st.nextToken())-1;
			cost = Integer.parseInt(st.nextToken());
			edges[i] = new Edge(from, to, cost);
		}
		
		int res = 0, maxCost = 0, cnt = 0;
		make();
		
		Arrays.sort(edges);
		for (int i = 0; i < E; i++) {
			Edge edge = edges[i];
			if(union(edge.from, edge.to)) {
				res += edge.cost;
				if(edge.cost > maxCost) maxCost = edge.cost;
				if(++cnt == N-1) break;
			}
		}
		
		System.out.println(res - maxCost);
	}

}

/*
 * ! 이미 연결된 간선이 하나의 그래프가 아닐 수 있음.
