public class Main {
	static BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
	static class Edge implements Comparable<Edge>{
		int from, to;
		double cost;
		
		public Edge(int from, int to, double cost) {
			this.from = from;
			this.to = to;
			this.cost = cost;
		}

		@Override
		public int compareTo(Edge o) {
