#include <iostream>
#include <vector>
#define INF 987654321
using namespace std;

bool getSegmentDir(pair<int, int> startPos, pair<int, int> endPos){
    if(startPos.first <= endPos.first) return true;
    else return false;
}

float getGradient(pair<int, int> startPos, pair<int, int> endPos){
    if((endPos.second - startPos.second)==0 && (endPos.first - startPos.first==0)) return 0;
    if(endPos.first - startPos.first==0) return INF;
    return static_cast< float >(endPos.second - startPos.second) /
        static_cast< float >(endPos.first - startPos.first);
}

int getDirection(pair<int, int> coords[3]){
    /**
     * 각 선분이 향하는 방향과 기울기로 방향을 알 수 있다.
     * 
     * 선분1 선분2
     * ->   -> : 기울기가 커지면 반시계(1)
     * ->   <- : 기울기가 커지면 시계(-1)
     * <-   -> : 기울기가 커지면 시계(-1)
     * <-   <- : 기울기가 커지면 반시계(1)
     * 기울기가 같다면 일직선(0)
    */
    bool segmentDirs[2] = {getSegmentDir(coords[0], coords[1]), getSegmentDir(coords[1], coords[2])};
    
    float gradients[2];

    if(segmentDirs[0]) gradients[0] = getGradient(coords[0], coords[1]);
    else  gradients[0] = getGradient(coords[1], coords[0]);

    if(segmentDirs[1]) gradients[1] = getGradient(coords[1], coords[2]);
    else  gradients[1] = getGradient(coords[2], coords[1]);

    if(gradients[0]==INF && gradients[1]==INF) return 0;
    float gradientDif = gradients[1]-gradients[0];
    if(gradientDif == 0) return 0;
    bool gradientGetBigger = gradientDif > 0;

    if(segmentDirs[0])
        if(segmentDirs[1])
            if(gradientGetBigger) return 1;
            else return -1;
        else
            if(gradientGetBigger) return -1;
            else return 1;
    else
        if(segmentDirs[1])
            if(gradientGetBigger) return -1;
            else return 1;
        else
            if(gradientGetBigger) return 1;
            else return -1;
}

int main(){
    pair<int, int> coords[3];
    for(int i=0; i<3; ++i)
        cin >> coords[i].first >> coords[i].second;
    cout << getDirection(coords) << '\n';
    return 0;
}

#include <iostream>
#include <vector>

using namespace std;

struct Piece{
    int number_;
    int row;
    int col;
    int dir;
};

int N, K;
bool isOver = false;
vector<Piece *> pieces;
vector<vector<int>> boardColor;
vector<vector<vector<Piece *>>> boardStack;
vector<pair<int, int>> ds = {{0, 1}, {0, -1}, {-1, 0}, {1, 0}};

void changeDir(Piece *curPiece);
void movePiece(Piece *curPiece);
void printBoard();

int main(){    
    cin >> N >> K;

    boardColor = vector<vector<int>> (N, vector<int> (N));
    boardStack = vector<vector<vector<Piece *>>> (N, vector<vector<Piece *>> (N));

    // 입력
    for(int i=0; i<N; ++i)
        for(int j=0; j<N; ++j)
            cin >> boardColor[i][j];

    int row, col, dir;
    for(int i=0; i<K; ++i){
        cin >> row >> col >> dir;
        Piece *newPiece = new Piece;
        newPiece->number_ = i;
        newPiece->row = row-1;
        newPiece->col = col-1;
        newPiece->dir = dir-1;

        pieces.push_back(newPiece);
        boardStack[row-1][col-1].push_back(newPiece);
    }

    // 실행
    int turn = 0;
    while(!isOver && turn <= 1000){
        for(int i=0; i<K; ++i) movePiece(pieces[i]);
        ++turn;
    }

    if(turn > 1000) cout << -1 << endl;
    else cout << turn << endl;

    return 0;
}

void printBoard(){
    for(int l=0; l<N; ++l){
        for(int j=0; j<N; ++j){
            for(int k=0; k<boardStack[l][j].size(); ++k)
                cout << boardStack[l][j][k]->number_;
            cout << " | ";
        }
        cout << "\n";
    }
}

void changeDir(Piece *curPiece){
    if(curPiece->dir%2==0) ++curPiece->dir;
    else --curPiece->dir;
    pair<int, int> nextPos = {curPiece->row+ds[curPiece->dir].first, curPiece->col+ds[curPiece->dir].second};
    if(nextPos.first<0 || nextPos.first>=N) return;
    if(nextPos.second<0 || nextPos.second>=N) return;
    if(boardColor[nextPos.first][nextPos.second] != 2) movePiece(curPiece);
    return;
};

void movePiece(Piece *curPiece){
    // printBoard();
    pair<int, int> nextPos = {curPiece->row+ds[curPiece->dir].first, curPiece->col+ds[curPiece->dir].second};

    if((nextPos.first<0) || (nextPos.first>=N) || (nextPos.second<0) || (nextPos.second>=N)){ // 벽
        changeDir(curPiece);
        return;
    }

    switch(boardColor[nextPos.first][nextPos.second]){
        case 0:{ // 흰색: 나부터 위로 쌓인 말들을 그대로 옮김. => 스택을 다 pop하고 push한(뒤집은) temp stack을 다시 목표 스택에 pop하고 push
            vector<Piece *> tempStack;
            while(boardStack[curPiece->row][curPiece->col].size()>0){
                Piece *movingPiece = boardStack[curPiece->row][curPiece->col].back();
                tempStack.push_back(movingPiece);
                boardStack[curPiece->row][curPiece->col].pop_back();

                // 좌표 업데이트
                movingPiece->row = nextPos.first;
                movingPiece->col = nextPos.second;
                if(movingPiece == curPiece) break;
            }
            while(tempStack.size()>0){
                boardStack[nextPos.first][nextPos.second].push_back(tempStack.back());
                tempStack.pop_back();
            }
            if(boardStack[nextPos.first][nextPos.second].size()>=4) isOver = true;
            break;
        }
        case 1:{ // 빨간색: 나부터 위로 쌓인 말들을 반대 순서로 옮김. => 스택을 목표 스택에 pop해서 push 반복
            while(boardStack[curPiece->row][curPiece->col].size()>0){
                Piece *movingPiece = boardStack[curPiece->row][curPiece->col].back();
                boardStack[nextPos.first][nextPos.second].push_back(movingPiece);
                boardStack[curPiece->row][curPiece->col].pop_back();

                //좌표 업데이트
                movingPiece->row = nextPos.first;
                movingPiece->col = nextPos.second;
                if(boardStack[nextPos.first][nextPos.second].size()>=4) isOver = true;
                if(movingPiece == curPiece) break;
            }
            break;
        }
        case 2:{ // 파란색: 방향을 반대로 바꿈. 반대가 파란색이나 맵 끝이 아닐 경우 이동
            changeDir(curPiece);
            break;
        }
    }
}

