vector<int> getBingo(char letter, string board){
    // board에 있는 letter의 빙고 개수
    vector<int> result;

    // 가로 빙고
    int tmp=0;
    for(int i=0; i<3; ++i){ // 행
        for(int j=0; j<3; ++j){ // 열
            if(board[i*3 + j] != letter) break;
            if(j==2) ++tmp;
        }
    }
    result.push_back(tmp);

    tmp = 0;
    // 세로 빙고
    for(int i=0; i<3; ++i){ // 열
        for(int j=0; j<3; ++j){ // 행
            if(board[j*3 + i] != letter) break;
            if(j==2) ++tmp;
        }
    }
    result.push_back(tmp);

    tmp = 0;
    // 대각선(우하) 빙고
    for(int i=0; i<3; ++i){
        if(board[i*3 + i] != letter) break;
        if(i==2) ++tmp;
    }
    result.push_back(tmp);

    tmp = 0;
    // 대각선(우상) 빙고
    for(int i=0; i<3; ++i){
        if(board[(2-i)*3 + i] != letter) break;
        if(i==2) ++tmp;
    }
    result.push_back(tmp);

    return result;
}

bool getIsXX(string board, vector<int> bingosX){
