 * 1. 방향은 양옆으로만 꺾을 수 있다. 뒤로 갈 수 없다.
 * 2. 거울은 무제한. 놓을 수 없는 곳이 있음(방향을 전환할 수 없는 곳)
 * 
 * 그냥 BFS 하고 꺾은 횟수 기록
 * ! 최소 꺾횟인지 어떻게 판단?
 * 가장 빨리 들어오면 가장 적은 거울 개수인가? x 별로 상관 없다.
 * 꺾횟 제한하기? 0~n^2 ㄱㄱㄱㄱ
*/
int n;
vector<vector<char>> room;
pair<int, int> exitDoor;
vector<pair<int, int>> ds = {{0, 1}, {0, -1}, {1, 0}, {-1, 0}};

bool bfs(int befY, int befX, int y, int x, int n_mirror){
    if(y < 0 || y >= n) return false;
    if(x < 0 || x >= n) return false;
    if(room[y][x] == '*') return false;
    if(room[y][x] == '#') return true;

    bool result = false;
    int newY, newX, dy = y-befY, dx = x-befX;
    if(n_mirror>0 && room[y][x]=='!'){
        for(pair<int, int> d: ds){
            newY = y+d.first;
            newX = x+d.second;
            if(dy == -d.first && dx == -d.second) continue; // 뒤로 반사
            if(dy == d.first && dx == d.second)
                result = result || bfs(y, x, newY, newX, n_mirror);
            else
                result = result || bfs(y, x, newY, newX, n_mirror-1);
        }
        return result;
    }
    else{
        newY = y + dy;
        newX = x + dx;
        return bfs(y, x, newY, newX, n_mirror);
    }
}

int main(){
    cin >> n;
    room = vector<vector<char>> (n, vector<char> (n));
    pair<int, int> entrance = {-1, -1};

    for(int i=0; i<n; ++i){
        for(int j=0; j<n; ++j){
        	char ch = cin.get();
            if(ch == '\n') ch = cin.get();
        	room[i][j] = ch;

            if(ch != '#') continue;
            if(entrance.first==-1){
                entrance = make_pair(i, j);
                room[i][j] = '.';
            }
            else exitDoor = make_pair(i, j);
        }
    }

    bool result;
    for(int i=0; i<n*n-1; ++i){
        result = false;
        for(pair<int, int> dir: ds){
            result = result ||
                bfs(
                    entrance.first,
                    entrance.second,
                    entrance.first+dir.first,
                    entrance.second+dir.second,
                    i
                );
        }
        if(result){
            cout << i << endl;
            break;
        }
    }


    return 0;
}

