    cin >> N;

    board = vector<vector<int>> (N, vector<int> (N));

    for(row=0; row<N; ++row){
        for(col=0; col<N; ++col){
            cin >> board[row][col];
        }
    }

    DFS(0);

    cout << score << endl;

    return 0;
}

