// 문자열 해시테이블

struct trie{
    int count = 0;
    unordered_map<char, trie *> dictionary;
};

float result;
void dfs(trie *current){
    for(auto iter: current->dictionary){
        if(iter.second->count != current->count) result +=iter.second->count ;
        dfs(iter.second);
    }
}

int main(){
    ios::sync_with_stdio(0), cin.tie(0);
    cout << setprecision(2) << fixed << showpoint;
    int n, i, j;
    while(cin >> n){
        vector<string> words (n);

        trie *root = new trie();
        trie *current = root;
        root->count = 0;
        root->dictionary.clear();

        for(i=0; i<n; ++i)
            cin >> words[i];
        
        for(string word: words){
            current = root;
            for(char c: word){
                if(current->dictionary.find(c) == current->dictionary.end()){ // 없음
                    current->dictionary[c] = new trie();
                }
                current= current->dictionary[c];
                current->count += 1;
            }
        }

        result = 0;
        dfs(root);
        cout << result/n << endl;
    }

    return 0;
}

// 구현과 완전탐색?

// 장애물이 아닌 위치에 공을 놓는다.
// 각 위치에 대해서
    // 더이상 이동할 수 없을 때까지 4방향 완전탐색을 한다. (DFS) 최소이동횟수를 넘는 경로 다이
    // 모든 곳을 탐색했다면 최소이동횟수를 저장한다.

// visit 배열

// 최소 이동횟수를 출력한다.

#include<iostream>
#include<vector>
using namespace std;

vector<vector<int>> ds = {{0, 1}, {1, 0}, {0, -1}, {-1, 0}};
vector<vector<char>> board(30, vector<char> (30));
int min_move = 1000001;
int holes;
int n, m;

void DFS(int y, int x, int move, int cnt){
    int newY, newX, curY = y, curX = x;
    if(move >= min_move) return;
    // cout << curY << curX << endl;
    vector<vector<int>> visit = {};
    bool isStuck = true;
    for(vector<int> d : ds){
        newY = y+d[0];
        newX = x+d[1];
        if(
            newY < 0 || newX < 0 ||
            newY >= n ||
            newX >= m ||
            board[newY][newX] == '*'
        )
            continue;
        
        isStuck = false;
        if(move >= min_move-1) return;
        int newCnt = cnt;

        // d방향으로 이동
        while(
            !(newY < 0 || newX < 0 ||
            newY >= n || 
            newX >= m ||
            board[newY][newX] == '*')
        ){
            ++newCnt;

            curY = newY;
            curX = newX;
            visit.push_back({newY, newX});
            board[curY][curX] = '*';

            newY = curY+d[0];
            newX = curX+d[1];
        }
        DFS(curY, curX, move+1, newCnt);
        for(auto v:visit)
            board[v[0]][v[1]] = '.';
    }
    if(isStuck)
        if(cnt == holes) min_move = move < min_move? move:min_move;
        // cout << "! " << move << endl;
}

int main(){
    int i, j, t = 0;
    while(true){
        ++t;
        min_move = 1000001;

        cin >> n >> m;
        if (cin.eof())
            break;

        vector<vector<int>> dots = {};

        holes = 0;
        for(i=0; i<n; ++i) for(j=0; j<m; ++j){
            cin >> board[i][j];
            if(board[i][j] == '.') {
                ++holes;
                dots.push_back({i, j});
            }
        }

        // 장애물이 아닌 위치에 공을 놓는다.
        // 각 위치에 대해서
        for(vector<int> dot: dots){
            board[dot[0]][dot[1]] = '*';
            DFS(dot[0], dot[1], 0, 1);
            board[dot[0]][dot[1]] = '.';
        }
        
        // 최소 이동횟수를 출력한다.
        cout << "Case " << t << ": " << (min_move==1000001?-1:min_move) << endl;
    }
    
    return 0;
}

/*
    각 칸의 최대 점수와, 그 visit 저장.
    새 칸에 접근할 때 그 칸의 최대 점수에 대한 visits를 다 가지고 있다면 죽음.
*/

#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

vector<vector<int>> d = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};

int DFS(int y, int x, int h, int w, int point, vector<char> visits, vector<vector<char>> &alphamap, vector<vector<vector<char>>> &points){
    // cout << y << x << endl;
    int maxPoint = point;
    int tmpPoint;
    //상하좌우
    for(vector<int> yx : d){
        int newY = y + yx[0];
        int newX = x + yx[1];
        if((newY >= 0) && (newY <= h-1)){
            if((newX >= 0) && (newX <= w-1)){
                if(find(visits.begin(), visits.end(), alphamap[newY][newX]) == visits.end()){ // 새로운 알파벳?
                    // bool go = false;
                    // if(points[newY][newX].size() <= point+1)
                    //     go = true;
                    // else for(char c : points[newY][newX]){
                    //     if(find(visits.begin(), visits.end(), c) == visits.end()){
                    //         go=true;
                    //         break;
                    //     }
                    // }
                    visits.push_back(alphamap[newY][newX]);
                    if(visits != points[newY][newX]){
                        points[newY][newX] = visits;
                        tmpPoint = DFS(newY, newX, h, w, point+1, visits, alphamap, points);
                        maxPoint = tmpPoint > maxPoint ? tmpPoint: maxPoint;
                    }
                    visits.pop_back();
                }
            }  
        }
    }

    return maxPoint;
}

int main(){
    int h, w, i, j;
    cin >> h >> w;

    vector<vector<char>> alphamap (h, vector<char> (w));
    vector<vector<vector<char>>> points (h, vector<vector<char>> (w));
    
    // 지도 입력
    char tmp[w];
    for(i=0; i<h; ++i){
        cin >> tmp;
        for(j=0; j<w; ++j)
            alphamap[i][j] = tmp[j];
    }

    cout << DFS(0, 0, h, w, 1, {alphamap[0][0]}, alphamap, points) << endl;

    return 0;
}

#include <iostream>
