    for(int k=0; k<m; ++k)
        for(i=0; i<m; ++i){
            can_lie = true;
            for(int v : party[i]){
                if (find(know_truth.begin(), know_truth.end(), v) != know_truth.end())
                    can_lie = false;
            }
            if(!can_lie){
                //party[i]에 온 사람들은 진실을 안다.
                for(int v : party[i]){
                    if (find(know_truth.begin(), know_truth.end(), v) == know_truth.end())
                        know_truth.push_back(v);
                }
            }
        }

    for(i=0; i<m; ++i){ // party
        can_lie = true;
        for(int v : party[i]){
            if (find(know_truth.begin(), know_truth.end(), v) != know_truth.end())
                can_lie = false;
        }
        if(can_lie) ++answer;
    }

    cout << answer << endl;

    return 0;
}

