int binarySearch(int x, int *xS, int st, int end){ // l은 xS의 원소의 개수가 아닌 점의 개수(원소개수/2)
  if(end - st < 0) return 0;
  int mid = (end+st)/2;

  if(xS[mid]==x)
    return 1;
  else if(xS[mid] < x)
      return binarySearch(x, xS, mid+1, end);
  else
    return binarySearch(x, xS, st, mid-1);
}

