long long factorial(int num){
  long long res = 1;
  for(int i=0; i<num; i++){
    res *= i+1;
    res %= P;
  }
  return res;
}

long long involute(long long a, long long b){
  if(b==1) return a%P;
  long long devAns = involute(a, b/2);
  devAns *= devAns;
  devAns %= P;
  if(b%2!=0){
    devAns *= a;
    devAns %= P;
  }
  return devAns;
}

