            ans[0] = arr[0];
            ans[1] = '\n';
            return ans;
        }

        else{ //박스(arr)가 여러 문자로 채워져있을 경우, 박스를 4등분하여 각 박스에 대해 cut 호출, 리턴 값(char*) 참조하여 ans 뒤에 문자열 복사
