                    for (k=0; k<nl*nl; k++){
                        tArr[k] = arr[i*l*nl+j*nl+(int)((int)(k/nl)*l)+k%nl];
                    }
                    temp = cut(tArr,nl);
                    k = 0;
                    while (temp[k]!='\n'){ //ans에 temp append -> while temp[k]!='\n'로 변경
                        ans[ansIdx]=temp[k];
                        ansIdx++;
                        k++;
                    }
                    free(tArr);
                    free(temp);
                }
            }
        }
    }
    //return "(ans)"
